const { MongoClient } = require('./web/node_modules/mongodb');

/**
 * Synthetic Actionables Cleanup Script
 *
 * Removes all synthetic actionables generated by generate-synthetic-actionables.js
 * Identifies synthetic records by the synthetic=true flag.
 *
 * This script:
 * 1. Finds all documents marked as synthetic
 * 2. Removes them from the actionables collection
 * 3. Reports what was deleted
 *
 * Usage:
 *   MONGO_URI=<uri> MONGO_DB=<db> node reset-synthetic-actionables.js
 */

const DEFAULT_URI = process.env.MONGO_URI
    || process.env.MONGODB_URI
    || "mongodb+srv://nitishsancs_db_user:OnHAmRujzopi4EpD@govinda.mdyhulj.mongodb.net/?appName=govinda";
const DEFAULT_DB = process.env.MONGO_DB || process.env.BACKEND_DB_NAME || "govinda_v2";

async function resetSyntheticActionables() {
    const uri = DEFAULT_URI;
    const client = new MongoClient(uri);

    try {
        await client.connect();
        console.log('Connected to MongoDB Atlas');

        const db = client.db(DEFAULT_DB);
        const col = db.collection('actionables');

        // Find all synthetic documents
        const syntheticDocs = await col.find({ synthetic: true }).toArray();
        console.log(`\nFound ${syntheticDocs.length} synthetic documents to remove.`);

        let totalRemoved = 0;

        // Delete each synthetic document
        for (const doc of syntheticDocs) {
            const result = await col.deleteOne({ _id: doc._id });
            if (result.deletedCount > 0) {
                const itemCount = doc.actionables?.length || 0;
                totalRemoved += itemCount;
                console.log(`  ✓ Removed doc_id=${doc._id} (${itemCount} actionables)`);
            }
        }

        console.log(`\n✅ Cleanup complete.`);
        console.log(`   Documents deleted : ${syntheticDocs.length}`);
        console.log(`   Total actionables removed : ${totalRemoved}`);

        // Verify deletion
        const remainingSynthetic = await col.find({ synthetic: true }).toArray();
        if (remainingSynthetic.length === 0) {
            console.log(`\n✨ All synthetic data has been successfully removed.`);
        } else {
            console.log(`\n⚠️  Warning: ${remainingSynthetic.length} synthetic documents still exist.`);
        }

    } catch (error) {
        console.error('Error:', error);
    } finally {
        await client.close();
        console.log('\nConnection closed');
    }
}

resetSyntheticActionables();
